const model = $input.first().json.model || '';
const audioPath = $input.first().json.audio_path || '';
const audio = $input.first().json.audio || '';

// Path traversal detection: check for ../, ..\\, and encoded variants
const pathTraversalPattern = /(\.\.[/\\\\]|%2e%2e[/\\\\]|\.\.\\\\x5c)/i;

// Check model name (alphanumeric, dash, underscore only - NO backslashes)
const validModelPattern = /^[a-zA-Z0-9_-]+$/;

if (!model) {
  throw new Error('Missing required field: model');
}
if (!audio && !audioPath) {
  throw new Error('Missing required field: audio or audio_path');
}
if (pathTraversalPattern.test(audioPath)) {
  throw new Error('Path traversal detected: audio_path must not contain directory traversal sequences');
}
if (!validModelPattern.test(model)) {
  throw new Error('Invalid model name: must be alphanumeric, dash, or underscore only');
}
if (model.length > 100) {
  throw new Error('Model name too long: max 100 characters');
}

return [{
  json: {
    model: model,
    audio: audio,
    audio_path: audioPath,
    channel: $input.first().json.channel || '#general',
    pitch: $input.first().json.pitch || 0,
    f0_method: $input.first().json.f0_method || 'rmvpe'
  }
}];

// Process RVC conversion response
const body = $input.first().json || {};
const validatedInput = $('Validate Input').first().json || {};

const downloadUrl = body.download_url || body.url || '';
const success = !!downloadUrl;

return [{
  json: {
    success: success,
    model: validatedInput.model || 'unknown',
    pitch: validatedInput.pitch || 0,
    f0_method: validatedInput.f0_method || 'rmvpe',
    download_url: downloadUrl,
    channel: validatedInput.channel || '#general',
    timestamp: new Date().toISOString()
  }
}];
